const normalizeUrl = (value) => {
  if (typeof value !== 'string') return '';

  const raw = value.trim();
  if (!raw) return '';

  try {
    const parsed = new URL(raw);
    const normalizedPath = parsed.pathname.replace(/\/+$|^$/, '/');
    return `${parsed.protocol.toLowerCase()}//${parsed.hostname.toLowerCase()}${normalizedPath}${parsed.search}`;
  } catch {
    return raw.replace(/\/+$|^$/, '/');
  }
};

const addProcessedOffer = (offer, processedUrls, processedIds) => {
  const offerUrl = normalizeUrl(
    offer?.origineOffre?.urlOrigine ??
    offer?.origineOffre?.url ??
    offer?.urlOrigine ??
    offer?.url
  );

  if (offerUrl) {
    processedUrls.add(offerUrl);
  }

  const offerId = offer?.id != null ? String(offer.id).trim() : '';
  if (offerId) {
    processedIds.add(offerId);
  }
};

const processedUrls = new Set();
const processedIds = new Set();

for (const item of $input.all()) {
  const json = item?.json ?? {};

  const directUrl = json.URLS ?? json.url ?? json.Url ?? json.urls;
  const normalizedDirectUrl = normalizeUrl(directUrl);
  if (normalizedDirectUrl) {
    processedUrls.add(normalizedDirectUrl);
  }

  const directId = json.id != null ? String(json.id).trim() : '';
  if (directId) {
    processedIds.add(directId);
  }

  if (Array.isArray(json.resultats)) {
    for (const offer of json.resultats) {
      addProcessedOffer(offer, processedUrls, processedIds);
    }
  }

  if (Array.isArray(json.results)) {
    for (const resultBlock of json.results) {
      if (Array.isArray(resultBlock?.resultats)) {
        for (const offer of resultBlock.resultats) {
          addProcessedOffer(offer, processedUrls, processedIds);
        }
      } else if (resultBlock && typeof resultBlock === 'object') {
        addProcessedOffer(resultBlock, processedUrls, processedIds);
      }
    }
  }
}

const aggregated = $('📦 Aggregate: Jobs').first()?.json?.results;
const results = Array.isArray(aggregated) ? aggregated : [];

const filteredResults = results
  .map((responseItem) => {
    if (!Array.isArray(responseItem?.resultats)) {
      return responseItem;
    }

    const filteredOffers = responseItem.resultats.filter((offer) => {
      const offerUrl = normalizeUrl(
        offer?.origineOffre?.urlOrigine ??
        offer?.origineOffre?.url ??
        offer?.urlOrigine ??
        offer?.url
      );
      const offerId = offer?.id != null ? String(offer.id).trim() : '';

      const isProcessedByUrl = offerUrl && processedUrls.has(offerUrl);
      const isProcessedById = offerId && processedIds.has(offerId);

      return !(isProcessedByUrl || isProcessedById);
    });

    return {
      ...responseItem,
      resultats: filteredOffers
    };
  })
  .filter((responseItem) => !Array.isArray(responseItem?.resultats) || responseItem.resultats.length > 0);

return [
  {
    json: {
      results: filteredResults
    },
    pairedItem: {
      item: 0
    }
  }
];

