parameters.jsCode:
const application = $('✍️ Agent: Generate Application').item.json;
const payload = $('🧩 Build GitHub Branch Payload').item.json;

const responseBody = $json.body ?? $json;
const commitSha = responseBody.commit?.sha || responseBody.content?.sha || '';
const commitUrl = responseBody.commit?.html_url || '';
const updateStatusCode = Number($json.statusCode || 200);
const updateConflict = updateStatusCode === 409;

return [{
  json: {
    ...application,
    github: {
      repository: payload.repository,
      branchName: payload.branchName,
      commitSha,
      commitUrl,
      updateStatusCode,
      updateConflict
    },
    sendTo: payload.sendTo,
    jobUrl: payload.jobUrl,
    jobTitle: payload.jobTitle,
    company: payload.company,
    branchName: payload.branchName,
    githubOwner: payload.githubOwner,
    githubRepo: payload.githubRepo,
    token: payload.token,
    pdfPath: payload.pdfPath,
    targetWorkflowName: payload.targetWorkflowName,
    pollAttempt: 0,
    pollIntervalSeconds: payload.pollIntervalSeconds,
    pollMaxAttempts: payload.pollMaxAttempts
  }
}];

const config = $('⚙️ Configuration1').first().json;
const job = $('Loop Over Application').item.json.job ?? {};
const output = $json.output ?? {};

const slugify = (value) => String(value || 'unknown')
  .normalize('NFD')
  .replace(/[\u0300-\u036f]/g, '')
  .toLowerCase()
  .replace(/[^a-z0-9]+/g, '-')
  .replace(/^-+|-+$/g, '')
  .slice(0, 40) || 'unknown';

const companySlug = slugify(job.company || 'company');
const titleSlug = slugify(output.job_title || job.title || 'job');
const suffix = String($execution.id || Date.now()).slice(-8);
const branchName = `cv/${companySlug}-${titleSlug}-${suffix}`;

const repository = `${config.githubOwner}/${config.githubRepo}`;
const filePath = config.githubLocaleFilePath || 'locales/fr.yml';
const pdfPath = config.githubPdfPath || 'pdf/cv-fr-light.pdf';
const locale = config.targetLanguage || 'fr';
const nowIso = new Date().toISOString();
const entryKey = `${companySlug}-${titleSlug}-${suffix}`;

return [{
  json: {
    repository,
    githubOwner: config.githubOwner,
    githubRepo: config.githubRepo,
    baseBranch: config.githubBaseBranch || 'main',
    branchName,
    locale,
    filePath,
    pdfPath,
    entryKey,
    nowIso,
    sendTo: config.candidateEmail || 'etiennelescot@gmail.com',
    jobUrl: output.job_url || job.url || '',
    jobTitle: output.job_title || job.title || '',
    company: job.company || '',
    targetWorkflowName: config.githubActionWorkflowName || 'Build and Commit PDFs',
    pollIntervalSeconds: Number(config.githubActionPollSeconds || 30),
    pollMaxAttempts: Number(config.githubActionMaxPollAttempts || 20),
    prDraft: Boolean(config.githubPrDraft),
    token: config.githubToken || ''
  }
}];

const context = $('⏳ Wait: Poll GitHub Action').item.json;
const runs = Array.isArray($json.workflow_runs) ? $json.workflow_runs : [];
const targetWorkflowName = String(context.targetWorkflowName || 'Build and Commit PDFs');
const commitSha = String(context.github?.commitSha || context.commitSha || '').toLowerCase();

// Debug: log first 3 runs to understand what API returns
const debugRuns = runs.slice(0, 3).map(r => ({
  name: r.name,
  status: r.status,
  conclusion: r.conclusion,
  head_sha: r.head_sha?.slice(0, 7)
}));

// Match by workflow name AND commit SHA (most reliable)
let matchingRun = null;

if (commitSha) {
  // Primary: match by name + exact commit SHA
  matchingRun = runs.find((run) => 
    String(run.name || '') === targetWorkflowName &&
    String(run.head_sha || '').toLowerCase() === commitSha
  );
}

// Fallback: if no SHA match, take most recent run with matching name
if (!matchingRun) {
  matchingRun = runs.find((run) => String(run.name || '') === targetWorkflowName);
}

const pollAttempt = Number(context.pollAttempt || 0) + 1;
const pollMaxAttempts = Number(context.pollMaxAttempts || 20);
const completed = matchingRun?.status === 'completed' || pollAttempt >= pollMaxAttempts;

return [{
  json: {
    ...context,
    pollAttempt,
    targetWorkflowName,
    commitSha: commitSha || 'none',  // For debugging
    debugRuns,  // For debugging
    runId: matchingRun?.id ?? '',
    runStatus: matchingRun?.status ?? 'not_found',
    runConclusion: matchingRun?.conclusion ?? '',
    runHtmlUrl: matchingRun?.html_url ?? '',
    completed
  }
}];

for (const item of $input.all()) {
  const runUrl = item.json.runHtmlUrl ? ` (<a href="${item.json.runHtmlUrl}">run GitHub Action</a>)` : '';
  item.json.emailExtraMessage = `⚠️ Aucun PDF personnalisé n'a été trouvé pour cette offre${runUrl}.`;

  const fallbackText = `Aucun PDF personnalisé n'a été généré.\n\nOffre: ${item.json.jobUrl || ''}\nRun: ${item.json.runHtmlUrl || ''}\n`;
  const fallbackBase64 = Buffer.from(fallbackText, 'utf8').toString('base64');

  item.binary = item.binary || {};
  item.binary.data = {
    data: fallbackBase64,
    mimeType: 'text/plain',
    fileName: 'pdf-not-available.txt'
  };
}

return $input.all();

for (const item of $input.all()) {
  const conclusion = item.json.runConclusion || 'unknown';
  const runUrl = item.json.runHtmlUrl ? ` (<a href="${item.json.runHtmlUrl}">run GitHub Action</a>)` : '';
  item.json.emailExtraMessage = `❌ Le workflow GitHub Action a échoué (conclusion: ${conclusion})${runUrl}.`;

  const fallbackText = `Le workflow GitHub Action a échoué (${conclusion}).\n\nOffre: ${item.json.jobUrl || ''}\nRun: ${item.json.runHtmlUrl || ''}\n`;
  const fallbackBase64 = Buffer.from(fallbackText, 'utf8').toString('base64');

  item.binary = item.binary || {};
  item.binary.data = {
    data: fallbackBase64,
    mimeType: 'text/plain',
    fileName: 'pdf-generation-error.txt'
  };
}

return $input.all();
